// // This module implements a 4-bit down/up counter that decrements when the up signal is high and increments when the down signal is high.
module updown_counter(
	input clk,
	input reset,
	input up,
	input down,
	output reg [3:0] q);always @(posedge clk)
	begin
		if (reset)
			q <= 4'b0000;
		else if (up)
			q <= q + 1;
		else if (down)
			q <= q - 1;
	end
endmodule
